import type { EbayApiClient } from '../client.js';

/**
 * Analytics API - Sales and traffic analytics
 * Based on: docs/sell-apps/analytics-and-report/sell_analytics_v1_oas3.json
 */
export class AnalyticsApi {
  private readonly basePath = '/sell/analytics/v1';

  constructor(private client: EbayApiClient) {}

  /**
   * Get traffic report for listings
   * @throws Error if required parameters are missing or invalid
   */
  async getTrafficReport(dimension: string, filter: string, metric: string, sort?: string) {
    // Input validation
    if (!dimension || typeof dimension !== 'string') {
      throw new Error('dimension is required and must be a string');
    }
    if (!filter || typeof filter !== 'string') {
      throw new Error('filter is required and must be a string');
    }
    if (!metric || typeof metric !== 'string') {
      throw new Error('metric is required and must be a string');
    }
    if (sort !== undefined && typeof sort !== 'string') {
      throw new Error('sort must be a string when provided');
    }

    const params: Record<string, string> = {
      dimension,
      filter,
      metric,
    };
    if (sort) params.sort = sort;

    try {
      return await this.client.get(`${this.basePath}/traffic_report`, params);
    } catch (error) {
      throw new Error(
        `Failed to get traffic report: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Find all seller standards profiles
   * Endpoint: GET /seller_standards_profile
   * @throws Error if the request fails
   */
  async findSellerStandardsProfiles() {
    try {
      return await this.client.get(`${this.basePath}/seller_standards_profile`);
    } catch (error) {
      throw new Error(
        `Failed to find seller standards profiles: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Get a specific seller standards profile
   * Endpoint: GET /seller_standards_profile/{program}/{cycle}
   * @throws Error if required parameters are missing or invalid
   */
  async getSellerStandardsProfile(program: string, cycle: string) {
    // Input validation
    if (!program || typeof program !== 'string') {
      throw new Error('program is required and must be a string');
    }
    if (!cycle || typeof cycle !== 'string') {
      throw new Error('cycle is required and must be a string');
    }

    try {
      return await this.client.get(`${this.basePath}/seller_standards_profile/${program}/${cycle}`);
    } catch (error) {
      throw new Error(
        `Failed to get seller standards profile: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Get customer service metrics
   * Endpoint: GET /customer_service_metric/{customer_service_metric_type}/{evaluation_type}
   * @throws Error if required parameters are missing or invalid
   */
  async getCustomerServiceMetric(
    customerServiceMetricType: string,
    evaluationType: string,
    evaluationMarketplaceId: string
  ) {
    // Input validation
    if (!customerServiceMetricType || typeof customerServiceMetricType !== 'string') {
      throw new Error('customerServiceMetricType is required and must be a string');
    }
    if (!evaluationType || typeof evaluationType !== 'string') {
      throw new Error('evaluationType is required and must be a string');
    }
    if (!evaluationMarketplaceId || typeof evaluationMarketplaceId !== 'string') {
      throw new Error('evaluationMarketplaceId is required and must be a string');
    }

    const params = {
      evaluation_marketplace_id: evaluationMarketplaceId,
    };

    try {
      return await this.client.get(
        `${this.basePath}/customer_service_metric/${customerServiceMetricType}/${evaluationType}`,
        params
      );
    } catch (error) {
      throw new Error(
        `Failed to get customer service metric: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }
}

import axios from 'axios';
import { XMLBuilder, XMLParser } from 'fast-xml-parser';
import type { EbayApiClient } from '@/api/client.js';
import { apiLogger } from '@/utils/logger.js';

const COMPAT_LEVEL = '1451';
const SITE_ID = '0';

export class TradingApiClient {
  private restClient: EbayApiClient;
  private baseUrl: string;
  private parser: XMLParser;
  private builder: XMLBuilder;

  constructor(restClient: EbayApiClient) {
    this.restClient = restClient;
    const env = restClient.getConfig().environment;
    this.baseUrl = env === 'sandbox' ? 'https://api.sandbox.ebay.com' : 'https://api.ebay.com';

    this.parser = new XMLParser({
      ignoreAttributes: false,
      removeNSPrefix: true,
      parseTagValue: true,
      isArray: (_name: string) => {
        const arrayTags = [
          'Item',
          'Errors',
          'Error',
          'NameValueList',
          'Value',
          'ShippingServiceOptions',
          'InternationalShippingServiceOption',
          'PaymentMethods',
          'PictureURL',
          'CompatibilityList',
          'Variation',
        ];
        return arrayTags.includes(_name);
      },
    });

    this.builder = new XMLBuilder({
      ignoreAttributes: false,
      format: true,
      suppressEmptyNode: true,
    });
  }

  getBaseUrl(): string {
    return this.baseUrl;
  }

  async execute(
    callName: string,
    params: Record<string, unknown>
  ): Promise<Record<string, unknown>> {
    const token = await this.restClient.getOAuthClient().getAccessToken();

    const requestTag = `${callName}Request`;
    const responseTag = `${callName}Response`;

    const xmlObj: Record<string, unknown> = {};
    xmlObj[requestTag] = {
      '@_xmlns': 'urn:ebay:apis:eBLBaseComponents',
      ...params,
    };

    const xmlBody = `<?xml version="1.0" encoding="utf-8"?>\n${this.builder.build(xmlObj)}`;

    apiLogger.debug(`Trading API ${callName}`, { xmlBody });

    let response;
    try {
      response = await axios.post(`${this.baseUrl}/ws/api.dll`, xmlBody, {
        headers: {
          'X-EBAY-API-SITEID': SITE_ID,
          'X-EBAY-API-COMPATIBILITY-LEVEL': COMPAT_LEVEL,
          'X-EBAY-API-CALL-NAME': callName,
          'X-EBAY-API-IAF-TOKEN': token,
          'Content-Type': 'text/xml',
        },
        timeout: 30000,
      });
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : 'Unknown HTTP error';
      throw new Error(`Trading API ${callName} request failed: ${message}`, { cause: error });
    }

    let parsed: Record<string, unknown>;
    try {
      parsed = this.parser.parse(response.data) as Record<string, unknown>;
    } catch (e) {
      throw new Error(
        `Failed to parse Trading API ${callName} response: ${e instanceof Error ? e.message : String(e)}`,
        { cause: e }
      );
    }
    const result = (parsed[responseTag] || parsed) as Record<string, unknown>;

    // Log warnings without failing
    if (result.Ack === 'Warning') {
      apiLogger.warn(`Trading API ${callName} returned warnings`, {
        errors: result.Errors,
      });
    }

    // Check for eBay errors
    if (result.Ack === 'Failure' || result.Ack === 'PartialFailure') {
      const errors = result.Errors;
      const firstError = Array.isArray(errors) ? errors[0] : errors;
      const message =
        firstError?.ShortMessage || firstError?.LongMessage || 'Unknown Trading API error';
      throw new Error(message);
    }

    return result;
  }
}

import { EbayOAuthClient } from '@/auth/oauth.js';
import { getBaseUrl } from '@/config/environment.js';
import type { EbayApiError, EbayConfig } from '@/types/ebay.js';
import axios, { type AxiosError, type AxiosInstance, type AxiosRequestConfig } from 'axios';
import { logRequest, logResponse, logErrorResponse } from '@/utils/logger.js';

interface AxiosConfigWithRetry extends AxiosRequestConfig {
  __authRetryCount?: number;
  __retryCount?: number;
}

class RateLimitTracker {
  private requestTimestamps: number[] = [];
  private readonly windowMs = 60000;
  private readonly maxRequests = 5000;

  canMakeRequest(): boolean {
    const now = Date.now();
    this.requestTimestamps = this.requestTimestamps.filter(
      (timestamp) => now - timestamp < this.windowMs
    );
    return this.requestTimestamps.length < this.maxRequests;
  }

  recordRequest(): void {
    this.requestTimestamps.push(Date.now());
  }

  getStats(): { current: number; max: number; windowMs: number } {
    const now = Date.now();
    this.requestTimestamps = this.requestTimestamps.filter(
      (timestamp) => now - timestamp < this.windowMs
    );
    return {
      current: this.requestTimestamps.length,
      max: this.maxRequests,
      windowMs: this.windowMs,
    };
  }
}

export class EbayApiClient {
  private httpClient: AxiosInstance;
  private authClient: EbayOAuthClient;
  private baseUrl: string;
  private rateLimitTracker: RateLimitTracker;
  private config: EbayConfig;

  private getDefaultHeaders(): Record<string, string> {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      Accept: 'application/json',
    };
    if (this.config.contentLanguage) {
      headers['Content-Language'] = this.config.contentLanguage;
    }
    if (this.config.marketplaceId) {
      headers['X-EBAY-C-MARKETPLACE-ID'] = this.config.marketplaceId;
    }
    return headers;
  }

  constructor(
    config: EbayConfig,
    context?: {
      userId?: string;
      environment?: 'production' | 'sandbox';
    }
  ) {
    this.config = config;
    this.authClient = new EbayOAuthClient(config, context);
    this.baseUrl = getBaseUrl(config.environment);
    this.rateLimitTracker = new RateLimitTracker();

    this.httpClient = axios.create({
      baseURL: this.baseUrl,
      timeout: 30000,
      headers: this.getDefaultHeaders(),
    });

    this.httpClient.interceptors.request.use(async (config) => {
      if (!this.rateLimitTracker.canMakeRequest()) {
        const stats = this.rateLimitTracker.getStats();
        throw new Error(
          `Rate limit exceeded: ${stats.current}/${stats.max} requests in ${stats.windowMs}ms window.`
        );
      }
      const token = await this.authClient.getAccessToken();
      config.headers.Authorization = `Bearer ${token}`;
      this.rateLimitTracker.recordRequest();
      logRequest(
        config.method || 'GET',
        `${config.baseURL}${config.url}`,
        config.params as Record<string, unknown>,
        config.data
      );
      return config;
    });

    this.httpClient.interceptors.response.use(
      (response) => {
        const remaining = response.headers['x-ebay-c-ratelimit-remaining'];
        const limit = response.headers['x-ebay-c-ratelimit-limit'];
        logResponse(response.status, response.statusText, response.data, remaining, limit);
        return response;
      },
      async (error: AxiosError) => {
        const config = error.config as AxiosConfigWithRetry | undefined;
        if (error.response) {
          logErrorResponse(
            error.response.status,
            error.response.statusText,
            `${config?.baseURL}${config?.url}`,
            error.response.data
          );
        }

        if (error.response?.status === 401 && config) {
          const retryCount = config.__authRetryCount || 0;
          if (retryCount === 0) {
            config.__authRetryCount = 1;
            await this.authClient.refreshUserToken();
            const newToken = await this.authClient.getAccessToken();
            if (config.headers) {
              config.headers.Authorization = `Bearer ${newToken}`;
            }
            return await this.httpClient.request(config);
          }
          const ebayError = error.response?.data as EbayApiError;
          const errorMessage =
            ebayError.errors?.[0]?.longMessage ||
            ebayError.errors?.[0]?.message ||
            'Invalid access token';
          throw new Error(`${errorMessage}. Automatic token refresh failed.`);
        }

        if (error.response?.status === 429) {
          const retryAfter = error.response.headers['retry-after'];
          const waitTime = retryAfter ? parseInt(retryAfter) * 1000 : 60000;
          throw new Error(`eBay API rate limit exceeded. Retry after ${waitTime / 1000} seconds.`);
        }

        if (error.response?.status && error.response.status >= 500 && config) {
          const retryCount = config.__retryCount || 0;
          if (retryCount < 3) {
            config.__retryCount = retryCount + 1;
            const delay = Math.pow(2, retryCount) * 1000;
            await new Promise<void>((resolve) => {
              setTimeout(resolve, Math.min(delay, 5000));
            });
            return await this.httpClient.request(config);
          }
        }

        if (axios.isAxiosError(error) && error.response?.data) {
          const ebayError = error.response.data as EbayApiError;
          const errorMessage =
            ebayError.errors?.[0]?.longMessage || ebayError.errors?.[0]?.message || error.message;
          throw new Error(`eBay API Error: ${errorMessage}`);
        }

        throw error;
      }
    );
  }

  async initialize(): Promise<void> {
    await this.authClient.initialize();
  }

  isAuthenticated(): boolean {
    return this.authClient.isAuthenticated();
  }

  hasUserTokens(): boolean {
    return this.authClient.hasUserTokens();
  }

  async setUserTokens(
    accessToken: string,
    refreshToken: string,
    accessTokenExpiry?: number,
    refreshTokenExpiry?: number
  ): Promise<void> {
    await this.authClient.setUserTokens(
      accessToken,
      refreshToken,
      accessTokenExpiry,
      refreshTokenExpiry
    );
  }

  getTokenInfo() {
    return this.authClient.getTokenInfo();
  }

  getOAuthClient(): EbayOAuthClient {
    return this.authClient;
  }

  getRateLimitStats() {
    return this.rateLimitTracker.getStats();
  }

  getConfig(): EbayConfig {
    return this.config;
  }

  async refreshUserToken(): Promise<void> {
    await this.authClient.refreshUserToken();
  }

  async get<T = unknown>(url: string, params?: Record<string, unknown>): Promise<T> {
    const response = await this.httpClient.get<T>(url, { params });
    return response.data;
  }

  async post<T = unknown>(
    url: string,
    data?: unknown,
    params?: Record<string, unknown>
  ): Promise<T> {
    const response = await this.httpClient.post<T>(url, data, { params });
    return response.data;
  }

  async put<T = unknown>(
    url: string,
    data?: unknown,
    params?: Record<string, unknown>
  ): Promise<T> {
    const response = await this.httpClient.put<T>(url, data, { params });
    return response.data;
  }

  async delete<T = unknown>(url: string, params?: Record<string, unknown>): Promise<T> {
    const response = await this.httpClient.delete<T>(url, { params });
    return response.data;
  }

  async getWithFullUrl<T = unknown>(fullUrl: string, params?: Record<string, unknown>): Promise<T> {
    const token = await this.authClient.getAccessToken();
    const response = await axios.get<T>(fullUrl, {
      params,
      headers: {
        Authorization: `Bearer ${token}`,
        ...this.getDefaultHeaders(),
      },
      timeout: 30000,
    });
    return response.data;
  }
}

import type { EbayApiClient } from '../client.js';

/**
 * Feedback API - Manage buyer and seller feedback
 * Based on: docs/sell-apps/communication/commerce_feedback_v1_beta_oas3.json
 */
export class FeedbackApi {
  private readonly basePath = '/commerce/feedback/v1';

  constructor(private client: EbayApiClient) {}

  /**
   * Get items awaiting feedback
   * Endpoint: GET /awaiting_feedback
   * @throws Error if the request fails
   */
  async getAwaitingFeedback(filter?: string, limit?: number, offset?: number) {
    const params: Record<string, string | number> = {};

    if (filter !== undefined) {
      if (typeof filter !== 'string') {
        throw new Error('filter must be a string when provided');
      }
      params.filter = filter;
    }
    if (limit !== undefined) {
      if (typeof limit !== 'number' || limit < 1) {
        throw new Error('limit must be a positive number when provided');
      }
      params.limit = limit;
    }
    if (offset !== undefined) {
      if (typeof offset !== 'number' || offset < 0) {
        throw new Error('offset must be a non-negative number when provided');
      }
      params.offset = offset;
    }

    try {
      return await this.client.get(`${this.basePath}/awaiting_feedback`, params);
    } catch (error) {
      throw new Error(
        `Failed to get awaiting feedback: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Get feedback for a transaction
   * Endpoint: GET /feedback
   * @throws Error if required parameters are missing or invalid
   */
  async getFeedback(transactionId: string) {
    if (!transactionId || typeof transactionId !== 'string') {
      throw new Error('transactionId is required and must be a string');
    }

    try {
      return await this.client.get(`${this.basePath}/feedback`, {
        transaction_id: transactionId,
      });
    } catch (error) {
      throw new Error(
        `Failed to get feedback: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Get feedback rating summary
   * Endpoint: GET /feedback_rating_summary
   * @throws Error if the request fails
   */
  async getFeedbackRatingSummary() {
    try {
      return await this.client.get(`${this.basePath}/feedback_rating_summary`);
    } catch (error) {
      throw new Error(
        `Failed to get feedback rating summary: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Leave feedback for a buyer
   * Endpoint: POST /feedback
   * @throws Error if required parameters are missing or invalid
   */
  async leaveFeedbackForBuyer(feedbackData: Record<string, unknown>) {
    if (!feedbackData || typeof feedbackData !== 'object') {
      throw new Error('feedbackData is required and must be an object');
    }

    try {
      return await this.client.post(`${this.basePath}/feedback`, feedbackData);
    } catch (error) {
      throw new Error(
        `Failed to leave feedback: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Respond to feedback
   * Endpoint: POST /respond_to_feedback
   * @throws Error if required parameters are missing or invalid
   */
  async respondToFeedback(feedbackId: string, responseText: string) {
    if (!feedbackId || typeof feedbackId !== 'string') {
      throw new Error('feedbackId is required and must be a string');
    }
    if (!responseText || typeof responseText !== 'string') {
      throw new Error('responseText is required and must be a string');
    }

    try {
      return await this.client.post(`${this.basePath}/respond_to_feedback`, {
        feedback_id: feedbackId,
        response_text: responseText,
      });
    } catch (error) {
      throw new Error(
        `Failed to respond to feedback: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Get feedback summary
   * @deprecated Use getFeedbackRatingSummary() instead
   */
  async getFeedbackSummary() {
    return await this.getFeedbackRatingSummary();
  }
}

import type { EbayApiClient } from '../client.js';

/**
 * Message API - Buyer-seller messaging
 * Based on: docs/sell-apps/communication/commerce_message_v1_oas3.json
 */
export class MessageApi {
  private readonly basePath = '/commerce/message/v1';

  constructor(private client: EbayApiClient) {}

  /**
   * Bulk update conversation
   * Endpoint: POST /bulk_update_conversation
   * @throws Error if required parameters are missing or invalid
   */
  async bulkUpdateConversation(updateData: Record<string, unknown>) {
    if (!updateData || typeof updateData !== 'object') {
      throw new Error('updateData is required and must be an object');
    }

    try {
      return await this.client.post(`${this.basePath}/bulk_update_conversation`, updateData);
    } catch (error) {
      throw new Error(
        `Failed to bulk update conversation: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Get conversations
   * Endpoint: GET /conversation
   * @throws Error if the request fails
   */
  async getConversations(filter?: string, limit?: number, offset?: number) {
    const params: Record<string, string | number> = {};

    if (filter !== undefined) {
      if (typeof filter !== 'string') {
        throw new Error('filter must be a string when provided');
      }
      params.filter = filter;
    }
    if (limit !== undefined) {
      if (typeof limit !== 'number' || limit < 1) {
        throw new Error('limit must be a positive number when provided');
      }
      params.limit = limit;
    }
    if (offset !== undefined) {
      if (typeof offset !== 'number' || offset < 0) {
        throw new Error('offset must be a non-negative number when provided');
      }
      params.offset = offset;
    }

    try {
      return await this.client.get(`${this.basePath}/conversation`, params);
    } catch (error) {
      throw new Error(
        `Failed to get conversations: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Get a specific conversation
   * Endpoint: GET /conversation/{conversation_id}
   * @throws Error if required parameters are missing or invalid
   */
  async getConversation(conversationId: string) {
    if (!conversationId || typeof conversationId !== 'string') {
      throw new Error('conversationId is required and must be a string');
    }

    try {
      return await this.client.get(`${this.basePath}/conversation/${conversationId}`);
    } catch (error) {
      throw new Error(
        `Failed to get conversation: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Send a message
   * Endpoint: POST /send_message
   * @throws Error if required parameters are missing or invalid
   */
  async sendMessage(messageData: Record<string, unknown>) {
    if (!messageData || typeof messageData !== 'object') {
      throw new Error('messageData is required and must be an object');
    }

    try {
      return await this.client.post(`${this.basePath}/send_message`, messageData);
    } catch (error) {
      throw new Error(
        `Failed to send message: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Update a conversation
   * Endpoint: POST /update_conversation
   * @throws Error if required parameters are missing or invalid
   */
  async updateConversation(updateData: Record<string, unknown>) {
    if (!updateData || typeof updateData !== 'object') {
      throw new Error('updateData is required and must be an object');
    }

    try {
      return await this.client.post(`${this.basePath}/update_conversation`, updateData);
    } catch (error) {
      throw new Error(
        `Failed to update conversation: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Search for messages
   * @deprecated Use getConversations() instead
   */
  async searchMessages(filter?: string, limit?: number, offset?: number) {
    return await this.getConversations(filter, limit, offset);
  }

  /**
   * Get a specific message
   * @deprecated Use getConversation() instead
   */
  async getMessage(messageId: string) {
    return await this.getConversation(messageId);
  }

  /**
   * Reply to a message
   * @deprecated Use sendMessage() instead
   */
  async replyToMessage(messageId: string, messageContent: string) {
    return await this.sendMessage({
      conversation_id: messageId,
      message_content: messageContent,
    });
  }
}

import type { EbayApiClient } from '../client.js';

/**
 * Negotiation API - Buyer-seller negotiations and offers
 * Based on: docs/sell-apps/communication/sell_negotiation_v1_oas3.json
 */
export class NegotiationApi {
  private readonly basePath = '/sell/negotiation/v1';

  constructor(private client: EbayApiClient) {}

  /**
   * Find eligible items for a seller-initiated offer
   * Endpoint: GET /find_eligible_items
   * @throws Error if the request fails
   */
  async findEligibleItems(filter?: string, limit?: number, offset?: number) {
    const params: Record<string, string | number> = {};

    if (filter !== undefined) {
      if (typeof filter !== 'string') {
        throw new Error('filter must be a string when provided');
      }
      params.filter = filter;
    }
    if (limit !== undefined) {
      if (typeof limit !== 'number' || limit < 1) {
        throw new Error('limit must be a positive number when provided');
      }
      params.limit = limit;
    }
    if (offset !== undefined) {
      if (typeof offset !== 'number' || offset < 0) {
        throw new Error('offset must be a non-negative number when provided');
      }
      params.offset = offset;
    }

    try {
      return await this.client.get(`${this.basePath}/find_eligible_items`, params);
    } catch (error) {
      throw new Error(
        `Failed to find eligible items: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Send offer to interested buyers
   * Endpoint: POST /send_offer_to_interested_buyers
   * @throws Error if required parameters are missing or invalid
   */
  async sendOfferToInterestedBuyers(offerData: Record<string, unknown>) {
    if (!offerData || typeof offerData !== 'object') {
      throw new Error('offerData is required and must be an object');
    }

    try {
      return await this.client.post(`${this.basePath}/send_offer_to_interested_buyers`, offerData);
    } catch (error) {
      throw new Error(
