import type { TradingApiClient } from '@/api/client-trading.js';

interface ListingSummary {
  itemId: string;
  title: string;
  sku: string;
  quantity: number;
  quantityAvailable: number;
  currentPrice: number;
  watchCount: number;
  listingType: string;
}

interface ActiveListingsResult {
  listings: ListingSummary[];
  total: number;
  totalPages: number;
}

export class TradingApi {
  constructor(private client: TradingApiClient) {}

  async getActiveListings(page = 1, entriesPerPage = 50): Promise<ActiveListingsResult> {
    const result = await this.client.execute('GetMyeBaySelling', {
      ActiveList: {
        Sort: 'TimeLeft',
        Pagination: {
          EntriesPerPage: entriesPerPage,
          PageNumber: page,
        },
      },
    });

    const activeList = result.ActiveList as Record<string, unknown> | undefined;
    const itemArray = activeList?.ItemArray as Record<string, unknown> | null;
    const items = (itemArray?.Item as Record<string, unknown>[]) || [];
    const pagination = activeList?.PaginationResult as Record<string, unknown> | undefined;

    const listings: ListingSummary[] = items.map((item) => {
      const sellingStatus = item.SellingStatus as Record<string, unknown> | undefined;
      const currentPrice = sellingStatus?.CurrentPrice as
        | Record<string, unknown>
        | number
        | undefined;
      const priceValue =
        typeof currentPrice === 'object' && currentPrice !== null
          ? Number(currentPrice['#text'] || 0)
          : Number(currentPrice || 0);

      return {
        itemId: String((item.ItemID as string | number | null) ?? ''),
        title: String((item.Title as string | number | null) ?? ''),
        sku: String((item.SKU as string | number | null) ?? ''),
        quantity: Number(item.Quantity || 0),
        quantityAvailable: Number(item.QuantityAvailable || 0),
        currentPrice: priceValue,
        watchCount: Number(item.WatchCount || 0),
        listingType: String((item.ListingType as string | number | null) ?? ''),
      };
    });

    return {
      listings,
      total: Number(pagination?.TotalNumberOfEntries || 0),
      totalPages: Number(pagination?.TotalNumberOfPages || 0),
    };
  }

  async getListing(itemId: string): Promise<Record<string, unknown>> {
    if (!itemId) throw new Error('itemId is required');

    const result = await this.client.execute('GetItem', {
      ItemID: itemId,
      DetailLevel: 'ReturnAll',
    });

    const items = result.Item as Record<string, unknown>[];
    return items?.[0] || result;
  }

  async createListing(item: Record<string, unknown>): Promise<Record<string, unknown>> {
    return await this.client.execute('AddFixedPriceItem', { Item: item });
  }

  async reviseListing(
    itemId: string,
    fields: Record<string, unknown>
  ): Promise<Record<string, unknown>> {
    if (!itemId) throw new Error('itemId is required');

    return await this.client.execute('ReviseFixedPriceItem', {
      Item: { ...fields, ItemID: itemId },
    });
  }

  async endListing(itemId: string, reason = 'NotAvailable'): Promise<Record<string, unknown>> {
    if (!itemId) throw new Error('itemId is required');

    return await this.client.execute('EndFixedPriceItem', {
      ItemID: itemId,
      EndingReason: reason,
    });
  }

  async relistItem(
    itemId: string,
    modifications?: Record<string, unknown>
  ): Promise<Record<string, unknown>> {
    if (!itemId) throw new Error('itemId is required');

    return await this.client.execute('RelistFixedPriceItem', {
      Item: { ...modifications, ItemID: itemId },
    });
  }
}

import axios, { type AxiosInstance } from 'axios';
import { Redis } from '@upstash/redis';

// ── Shared interface ──────────────────────────────────────────────────────────

/** Common contract for all KV store backends. */
export interface KVStore {
  /** Human-readable identifier for the backend (e.g. "InMemoryKVStore", "CloudflareKVStore"). */
  readonly backendName: string;
  get<T>(key: string): Promise<T | null>;
  put(key: string, value: unknown, expirationTtl?: number): Promise<void>;
  delete(key: string): Promise<void>;
}

// ── In-memory backend ─────────────────────────────────────────────────────────

interface MemEntry {
  value: unknown;
  /** Unix ms timestamp after which the entry is expired. Undefined = never expires. */
  expiresAt?: number;
}

/**
 * Purely in-memory KV store with optional per-entry TTL.
 * Useful for local development, single-user setups, or when
 * EBAY_TOKEN_STORE_BACKEND=memory.
 * All data is lost on process restart.
 */
export class InMemoryKVStore implements KVStore {
  readonly backendName = 'InMemoryKVStore';
  private store = new Map<string, MemEntry>();

  get<T>(key: string): Promise<T | null> {
    const entry = this.store.get(key);
    if (!entry) return Promise.resolve(null);
    if (entry.expiresAt !== undefined && Date.now() > entry.expiresAt) {
      this.store.delete(key);
      return Promise.resolve(null);
    }
    return Promise.resolve(entry.value as T);
  }

  put(key: string, value: unknown, expirationTtl?: number): Promise<void> {
    this.store.set(key, {
      value,
      expiresAt: expirationTtl !== undefined ? Date.now() + expirationTtl * 1_000 : undefined,
    });
    return Promise.resolve();
  }

  delete(key: string): Promise<void> {
    this.store.delete(key);
    return Promise.resolve();
  }
}

// ── Cloudflare KV backend ─────────────────────────────────────────────────────

interface CacheEntry<T> {
  value: T;
  expiresAt: number;
}

/**
 * Cloudflare KV REST API backend with an in-memory read-through cache.
 * Used when EBAY_TOKEN_STORE_BACKEND=cloudflare-kv (the default for hosted deployments).
 */
export class CloudflareKVStore implements KVStore {
  readonly backendName = 'CloudflareKVStore';
  private client: AxiosInstance;
  private accountId: string;
  private namespaceId: string;
  /** In-memory read-through cache to avoid redundant Cloudflare KV API calls */
  private cache = new Map<string, CacheEntry<unknown>>();
  /** How long (ms) to hold a cached value before re-fetching from KV. Default: 5 minutes. */
  private cacheTtlMs: number;

  constructor(cacheTtlMs = 5 * 60 * 1_000) {
    this.cacheTtlMs = cacheTtlMs;
    this.accountId = process.env.CLOUDFLARE_ACCOUNT_ID || '';
    this.namespaceId = process.env.CLOUDFLARE_KV_NAMESPACE_ID || '';
    const apiToken = process.env.CLOUDFLARE_API_TOKEN || '';

    if (!this.accountId || !this.namespaceId || !apiToken) {
      throw new Error(
        'Cloudflare KV backend selected, but CLOUDFLARE_ACCOUNT_ID, CLOUDFLARE_KV_NAMESPACE_ID, and CLOUDFLARE_API_TOKEN must all be set.'
      );
    }

    this.client = axios.create({
      baseURL: `https://api.cloudflare.com/client/v4/accounts/${this.accountId}/storage/kv/namespaces/${this.namespaceId}`,
      headers: {
        Authorization: `Bearer ${apiToken}`,
        'Content-Type': 'application/json',
      },
      timeout: 30000,
    });
  }

  private isCacheValid(entry: CacheEntry<unknown>): boolean {
    return Date.now() < entry.expiresAt;
  }

  async get<T>(key: string): Promise<T | null> {
    // Serve from in-memory cache when still fresh
    const cached = this.cache.get(key);
    if (cached && this.isCacheValid(cached)) {
      return cached.value as T | null;
    }

    try {
      const response = await this.client.get(`/values/${encodeURIComponent(key)}`, {
        responseType: 'text',
      });
      const value = JSON.parse(response.data as string) as T;
      this.cache.set(key, { value, expiresAt: Date.now() + this.cacheTtlMs });
      return value;
    } catch (error) {
      if (axios.isAxiosError(error) && error.response?.status === 404) {
        // Cache the miss so we don't hammer KV for non-existent keys either
        this.cache.set(key, { value: null, expiresAt: Date.now() + this.cacheTtlMs });
        return null;
      }
      throw error;
    }
  }

  async put(key: string, value: unknown, expirationTtl?: number): Promise<void> {
    const params = expirationTtl ? { expiration_ttl: expirationTtl } : undefined;
    await this.client.put(`/values/${encodeURIComponent(key)}`, JSON.stringify(value), { params });

    // Keep the in-memory cache consistent with what we wrote.
    // If the KV entry has its own TTL, honour it for the cache as well.
    const cacheTtl = expirationTtl
      ? Math.min(expirationTtl * 1_000, this.cacheTtlMs)
      : this.cacheTtlMs;
    this.cache.set(key, { value, expiresAt: Date.now() + cacheTtl });
  }

  async delete(key: string): Promise<void> {
    await this.client.delete(`/values/${encodeURIComponent(key)}`);
    this.cache.delete(key);
  }

  /** Manually evict a single key from the local cache (e.g. after an external update). */
  invalidate(key: string): void {
    this.cache.delete(key);
  }

  /** Flush the entire in-memory cache. */
  flushCache(): void {
    this.cache.clear();
  }
}

// ── Upstash Redis backend ────────────────────────────────────────────────────

/**
 * Upstash Redis REST API backend with an in-memory read-through cache.
 * Used when EBAY_TOKEN_STORE_BACKEND=upstash-redis.
 */
export class UpstashRedisKVStore implements KVStore {
  readonly backendName = 'UpstashRedisKVStore';
  private client: Redis;
  private cache = new Map<string, CacheEntry<unknown>>();
  private cacheTtlMs: number;

  constructor(cacheTtlMs = 5 * 60 * 1_000) {
    this.cacheTtlMs = cacheTtlMs;
    const url = process.env.UPSTASH_REDIS_REST_URL || '';
    const token = process.env.UPSTASH_REDIS_REST_TOKEN || '';

    if (!url || !token) {
      throw new Error(
        'Upstash Redis backend selected, but UPSTASH_REDIS_REST_URL and UPSTASH_REDIS_REST_TOKEN must both be set.'
      );
    }

    this.client = new Redis({ url, token });
  }

  private isCacheValid(entry: CacheEntry<unknown>): boolean {
    return Date.now() < entry.expiresAt;
  }

  async get<T>(key: string): Promise<T | null> {
    const cached = this.cache.get(key);
    if (cached && this.isCacheValid(cached)) {
      return cached.value as T | null;
    }

    const value = await this.client.get<T>(key);
    this.cache.set(key, { value, expiresAt: Date.now() + this.cacheTtlMs });
    return value ?? null;
  }

  async put(key: string, value: unknown, expirationTtl?: number): Promise<void> {
    if (expirationTtl !== undefined) {
      await this.client.set(key, value, { ex: expirationTtl });
    } else {
      await this.client.set(key, value);
    }

    const cacheTtl = expirationTtl
      ? Math.min(expirationTtl * 1_000, this.cacheTtlMs)
      : this.cacheTtlMs;
    this.cache.set(key, { value, expiresAt: Date.now() + cacheTtl });
  }

  async delete(key: string): Promise<void> {
    await this.client.del(key);
    this.cache.delete(key);
  }

  invalidate(key: string): void {
    this.cache.delete(key);
  }

  flushCache(): void {
    this.cache.clear();
  }
}

// ── Singleton factory ─────────────────────────────────────────────────────────

/**
 * Process-level singleton KV store.
 *
 * All callers within the same Node.js process share one backend instance.
 * This is the root cause guard: it makes it impossible for two different
 * MultiUserAuthStore instances to accidentally resolve to different backends
 * (e.g. one reading EBAY_TOKEN_STORE_BACKEND before dotenv runs and one after).
 *
 * The singleton is lazy: it is created on the first call to `createKVStore()`
 * and reused for every subsequent call.
 *
 * For automated tests only, call `resetKVStoreSingleton()` between test cases
 * that need to swap the backend.
 */
let _kvStoreSingleton: KVStore | null = null;

/**
 * Returns (or lazily creates) the process-wide KV store singleton based on the
 * EBAY_TOKEN_STORE_BACKEND environment variable:
 *
 *   memory         → InMemoryKVStore   (no external dependencies, data lost on restart)
 *   cloudflare-kv  → CloudflareKVStore (requires CLOUDFLARE_* env vars)
 *   upstash-redis  → UpstashRedisKVStore (requires UPSTASH_REDIS_REST_* env vars)
 *
 * If the variable is unset or unrecognised, defaults to cloudflare-kv so that
 * existing hosted deployments continue to work without any config change.
 */
export function createKVStore(): KVStore {
  if (_kvStoreSingleton) {
    return _kvStoreSingleton;
  }

  const rawEnv = process.env.EBAY_TOKEN_STORE_BACKEND;
  const backend = (rawEnv ?? 'cloudflare-kv').toLowerCase().trim();

  // Log exactly once, at the point the singleton is first constructed.
  switch (backend) {
    case 'memory':
    case 'in-memory': {
      console.log(
        `[kv-store] EBAY_TOKEN_STORE_BACKEND="${rawEnv ?? ''}" → using InMemoryKVStore (no external KV calls)`
      );
      _kvStoreSingleton = new InMemoryKVStore();
      break;
    }
    case 'upstash-redis':
    case 'upstash':
    case 'redis': {
      console.log(
        `[kv-store] EBAY_TOKEN_STORE_BACKEND="${rawEnv ?? ''}" → using UpstashRedisKVStore (url="${process.env.UPSTASH_REDIS_REST_URL ?? '(unset)'}")`
      );
      _kvStoreSingleton = new UpstashRedisKVStore();
      break;
    }
    case 'cloudflare-kv':
    case 'cloudflare':
    default: {
      console.log(
        `[kv-store] EBAY_TOKEN_STORE_BACKEND="${rawEnv ?? '(unset)'}" → using CloudflareKVStore (accountId="${process.env.CLOUDFLARE_ACCOUNT_ID ?? '(unset)'}") — set EBAY_TOKEN_STORE_BACKEND=memory to disable`
      );
      _kvStoreSingleton = new CloudflareKVStore();
      break;
    }
  }

  return _kvStoreSingleton;
}

/**
 * **TEST USE ONLY** – resets (or replaces) the process-wide KV store singleton.
 *
 * Call this in `afterEach`/`beforeEach` when a test needs to control which
 * backend is in use without mutating `process.env.EBAY_TOKEN_STORE_BACKEND`.
 *
 * @param replacement  Optional KV store to install as the new singleton.
 *                     Pass `null` (default) to clear the singleton so that the
 *                     next `createKVStore()` call rebuilds it from env.
 */
export function resetKVStoreSingleton(replacement: KVStore | null = null): void {
  _kvStoreSingleton = replacement;
}

/**
 * OAuth metadata endpoints for MCP server
 * Implements RFC 9728 Protected Resource Metadata
 */

import type { Router } from 'express';
import { Router as createRouter } from 'express';
import type { ProtectedResourceMetadata, OAuthServerMetadata } from './oauth-types.js';

export interface MetadataConfig {
  /**
   * Resource server URL (e.g., "http://localhost:3000")
   */
  resourceServerUrl: string;

  /**
   * Authorization server URL or metadata
   */
  authServerMetadata: string | OAuthServerMetadata;

  /**
   * Scopes supported by this resource server
   */
  scopesSupported: string[];

  /**
   * Optional documentation URL for this resource server
   */
  resourceDocumentation?: string;

  /**
   * Resource name for display purposes
   */
  resourceName?: string;

  /**
   * eBay environment (production or sandbox) - optional
   * Used to indicate which eBay environment the server is configured for
   */
  ebayEnvironment?: 'production' | 'sandbox';

  /**
   * eBay-specific OAuth scopes - optional
   * Separate from MCP OAuth scopes, indicates what eBay API access is available
   */
  ebayScopes?: string[];
}

/**
 * Create Express router with OAuth metadata endpoints
 */
export function createMetadataRouter(config: MetadataConfig): Router {
  const router = createRouter();

  // RFC 9728: Protected Resource Metadata endpoint
  // Path: /.well-known/oauth-protected-resource
  router.get('/.well-known/oauth-protected-resource', (req, res) => {
    const authServers =
      typeof config.authServerMetadata === 'string'
        ? [config.authServerMetadata]
        : [config.authServerMetadata.issuer];

    const metadata: ProtectedResourceMetadata = {
      resource: config.resourceServerUrl,
      authorization_servers: authServers,
      scopes_supported: config.scopesSupported,
    };

    if (config.resourceDocumentation) {
      metadata.resource_documentation = config.resourceDocumentation;
    }

    res.json(metadata);
  });

  // Optional: Server info endpoint for debugging
  router.get('/.well-known/mcp-server-info', (req, res) => {
    const serverInfo: Record<string, unknown> = {
      name: config.resourceName || 'MCP Resource Server',
      version: '1.0.0',
      resource_url: config.resourceServerUrl,
      authorization_required: true,
      scopes_supported: config.scopesSupported,
      documentation: config.resourceDocumentation,
    };

    // Add eBay-specific information if provided
    if (config.ebayEnvironment) {
      serverInfo.ebay = {
        environment: config.ebayEnvironment,
        base_url:
          config.ebayEnvironment === 'production'
            ? 'https://api.ebay.com'
            : 'https://api.sandbox.ebay.com',
        scopes: config.ebayScopes || [],
        note: 'MCP OAuth scopes (scopes_supported) are separate from eBay API OAuth scopes (ebay.scopes)',
      };
    }

    res.json(serverInfo);
  });

  return router;
}

/**
 * Helper to get Protected Resource Metadata URL from server URL
 */
export function getProtectedResourceMetadataUrl(serverUrl: string): string {
  const url = new URL(serverUrl);
  url.pathname = '/.well-known/oauth-protected-resource';
  return url.toString();
}

/**
 * OAuth 2.1 middleware for Express
 * Implements RFC 6750 Bearer Token authentication
 */

import type { Request, Response, NextFunction } from 'express';
import type { TokenVerifier } from './token-verifier.js';
import type { VerifiedToken } from './oauth-types.js';

/**
 * Extended Express Request with verified token
 */
export interface AuthenticatedRequest extends Request {
  auth?: VerifiedToken;
}

export interface BearerAuthMiddlewareConfig {
  /**
   * Token verifier instance
   */
  verifier: TokenVerifier;

  /**
   * Protected Resource Metadata URL for WWW-Authenticate header
   */
  resourceMetadataUrl: string;

  /**
   * Realm for WWW-Authenticate header
   */
  realm?: string;
}

/**
 * Create Bearer token authentication middleware
 */
export function createBearerAuthMiddleware(config: BearerAuthMiddlewareConfig) {
  const realm = config.realm || 'mcp';

  return async (req: AuthenticatedRequest, res: Response, next: NextFunction): Promise<void> => {
    try {
      // Extract token from Authorization header
      const authHeader = req.headers.authorization;

      if (!authHeader) {
        sendUnauthorized(res, realm, config.resourceMetadataUrl, {
          error: 'invalid_token',
          error_description: 'No authorization header provided',
        });
        return;
      }

      // Check Bearer scheme
      const parts = authHeader.split(' ');
      if (parts.length !== 2 || parts[0] !== 'Bearer') {
        sendUnauthorized(res, realm, config.resourceMetadataUrl, {
          error: 'invalid_token',
          error_description: 'Invalid authorization header format. Expected: Bearer <token>',
        });
        return;
      }

      const token = parts[1];

      // Verify token
      try {
        const verifiedToken = await config.verifier.verifyToken(token);
        req.auth = verifiedToken;
        next();
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Token verification failed';

        sendUnauthorized(res, realm, config.resourceMetadataUrl, {
          error: 'invalid_token',
          error_description: errorMessage,
        });
      }
    } catch (error) {
      console.error('OAuth middleware error:', error);
      res.status(500).json({
        error: 'server_error',
        error_description: 'Internal server error during authentication',
      });
    }
  };
}

/**
 * Send 401 Unauthorized response with RFC 6750 compliant WWW-Authenticate header
 */
function sendUnauthorized(
  res: Response,
  realm: string,
  resourceMetadataUrl: string,
  challenge: {
    error?: string;
    error_description?: string;
    scope?: string;
  }
): void {
  // Build WWW-Authenticate header per RFC 6750
  let authenticateValue = `Bearer realm="${realm}", resource_metadata="${resourceMetadataUrl}"`;

  if (challenge.error) {
    authenticateValue += `, error="${challenge.error}"`;
  }

  if (challenge.error_description) {
    authenticateValue += `, error_description="${challenge.error_description}"`;
  }

  if (challenge.scope) {
    authenticateValue += `, scope="${challenge.scope}"`;
  }

  res.setHeader('WWW-Authenticate', authenticateValue);
  res.status(401).json({
    error: challenge.error || 'unauthorized',
    error_description: challenge.error_description || 'Authorization required',
  });
}

/**
 * Optional middleware to check specific scopes
 */
export function requireScopes(requiredScopes: string[]) {
  return (req: AuthenticatedRequest, res: Response, next: NextFunction): void => {
    if (!req.auth) {
      res.status(401).json({
        error: 'unauthorized',
        error_description: 'No authentication information found',
      });
      return;
    }

    const hasRequiredScopes = requiredScopes.every((scope) => req.auth!.scopes.includes(scope));

    if (!hasRequiredScopes) {
      res.status(403).json({
        error: 'insufficient_scope',
        error_description: `Missing required scopes: ${requiredScopes.join(', ')}`,
        required_scopes: requiredScopes,
        provided_scopes: req.auth.scopes,
      });
      return;
    }

    next();
  };
}

import axios from 'axios';
import { getOAuthTokenBaseUrl } from '@/config/environment.js';
import type {
  EbayAppAccessTokenResponse,
  EbayConfig,
  EbayUserToken,
  StoredTokenData,
} from '@/types/ebay.js';
import { MultiUserAuthStore } from '@/auth/multi-user-store.js';

export class EbayOAuthClient {
  private appAccessToken: string | null = null;
  private appAccessTokenExpiry = 0;
  private userTokens: StoredTokenData | null = null;
  private authStore = new MultiUserAuthStore();
  private authSource:
    | 'stored_user_tokens'
    | 'env_refresh_token_fallback'
    | 'authorization_code_exchange'
    | 'manual_set_user_tokens'
    | null = null;

  constructor(
    private config: EbayConfig,
    private context?: { userId?: string; environment?: 'production' | 'sandbox' }
  ) {}

  private getTokenEndpoint(): string {
    return `${getOAuthTokenBaseUrl(this.config.environment)}/identity/v1/oauth2/token`;
  }

  async initialize(): Promise<void> {
    if (this.context?.userId && this.context.environment) {
      const stored = await this.authStore.getUserTokens(
        this.context.userId,
        this.context.environment
      );
      if (stored?.tokenData) {
        this.userTokens = stored.tokenData;
        this.authSource = 'stored_user_tokens';
        return;
      }
    }

    // Fallback: load from EBAY_USER_REFRESH_TOKEN environment variable
    const envRefreshToken = process.env.EBAY_USER_REFRESH_TOKEN;
    if (envRefreshToken) {
      try {
        const authUrl = this.getTokenEndpoint();
        const credentials = Buffer.from(
          `${this.config.clientId}:${this.config.clientSecret}`
        ).toString('base64');

        const response = await axios.post<EbayUserToken>(
          authUrl,
          new URLSearchParams({
            grant_type: 'refresh_token',
            refresh_token: envRefreshToken,
          }).toString(),
          {
            headers: {
              'Content-Type': 'application/x-www-form-urlencoded',
              Authorization: `Basic ${credentials}`,
            },
          }
        );

        const tokenData = response.data;
        const now = Date.now();
        this.userTokens = {
          clientId: this.config.clientId,
          clientSecret: this.config.clientSecret,
          redirectUri: this.config.redirectUri,
          userAccessToken: tokenData.access_token,
          userRefreshToken: tokenData.refresh_token || envRefreshToken,
          tokenType: tokenData.token_type,
          userAccessTokenExpiry: now + tokenData.expires_in * 1000,
          userRefreshTokenExpiry: tokenData.refresh_token_expires_in
            ? now + tokenData.refresh_token_expires_in * 1000
            : now + 18 * 30 * 24 * 60 * 60 * 1000,
          scope: tokenData.scope,
        };
        this.authSource = 'env_refresh_token_fallback';
      } catch {
        // If refresh fails, leave userTokens as null
      }
    }
  }

  hasUserTokens(): boolean {
    return this.userTokens !== null;
  }

  private isUserAccessTokenExpired(tokens: StoredTokenData): boolean {
    return tokens.userAccessTokenExpiry ? Date.now() >= tokens.userAccessTokenExpiry : true;
  }

  private isUserRefreshTokenExpired(tokens: StoredTokenData): boolean {
    return tokens.userRefreshTokenExpiry ? Date.now() >= tokens.userRefreshTokenExpiry : true;
  }

  private async persistUserTokens(): Promise<void> {
    if (this.context?.userId && this.context.environment && this.userTokens) {
      await this.authStore.saveUserTokens(
        this.context.userId,
        this.context.environment,
        this.userTokens
      );
    }
  }

  async getAccessToken(): Promise<string> {
    if (this.userTokens) {
      if (!this.isUserAccessTokenExpired(this.userTokens)) {
        return this.userTokens.userAccessToken;
      }
      if (!this.isUserRefreshTokenExpired(this.userTokens)) {
        await this.refreshUserToken();
        return this.userTokens.userAccessToken;
      }
      throw new Error(
        'User authorization expired. Re-authorize through browser OAuth and update your MCP connection token.'
      );
    }

    if (this.appAccessToken && Date.now() < this.appAccessTokenExpiry) {
      return this.appAccessToken;
    }

    await this.getOrRefreshAppAccessToken();
    return this.appAccessToken!;
  }

  async setUserTokens(
    accessToken: string,
    refreshToken: string,
    accessTokenExpiry?: number,
    refreshTokenExpiry?: number
  ): Promise<void> {
    const now = Date.now();
    this.userTokens = {
      clientId: this.config.clientId,
      clientSecret: this.config.clientSecret,
      redirectUri: this.config.redirectUri,
      userAccessToken: accessToken,
      userRefreshToken: refreshToken,
      tokenType: 'Bearer',
      userAccessTokenExpiry: accessTokenExpiry ?? now + 7200 * 1000,
      userRefreshTokenExpiry: refreshTokenExpiry ?? now + 18 * 30 * 24 * 60 * 60 * 1000,
    };
    this.authSource = 'manual_set_user_tokens';
    await this.persistUserTokens();
  }

  async getOrRefreshAppAccessToken(): Promise<string> {
    if (this.appAccessToken && Date.now() < this.appAccessTokenExpiry) {
      return this.appAccessToken;
    }

    const authUrl = this.getTokenEndpoint();
    const credentials = Buffer.from(`${this.config.clientId}:${this.config.clientSecret}`).toString(
      'base64'
    );

    const response = await axios.post<EbayAppAccessTokenResponse>(
      authUrl,
      new URLSearchParams({
        grant_type: 'client_credentials',
        scope: 'https://api.ebay.com/oauth/api_scope',
      }).toString(),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          Authorization: `Basic ${credentials}`,
        },
      }
    );

    this.appAccessToken = response.data.access_token;
    this.appAccessTokenExpiry = Date.now() + (response.data.expires_in - 60) * 1000;
    return this.appAccessToken;
  }

  async exchangeCodeForToken(code: string): Promise<EbayUserToken> {
    if (!this.config.redirectUri) {
      throw new Error('Redirect URI is required for authorization code exchange');
    }

    const tokenUrl = this.getTokenEndpoint();
    const credentials = Buffer.from(`${this.config.clientId}:${this.config.clientSecret}`).toString(
      'base64'
    );

    try {
      const response = await axios.post<EbayUserToken>(
        tokenUrl,
        new URLSearchParams({
          grant_type: 'authorization_code',
          code,
          redirect_uri: this.config.redirectUri,
        }).toString(),
        {
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
            Authorization: `Basic ${credentials}`,
          },
        }
      );

      const tokenData = response.data;
      const now = Date.now();
      this.userTokens = {
        clientId: this.config.clientId,
        clientSecret: this.config.clientSecret,
        redirectUri: this.config.redirectUri,
        userAccessToken: tokenData.access_token,
        userRefreshToken: tokenData.refresh_token,
        tokenType: tokenData.token_type,
        userAccessTokenExpiry: now + tokenData.expires_in * 1000,
        userRefreshTokenExpiry: now + tokenData.refresh_token_expires_in * 1000,
        scope: tokenData.scope,
      };
      this.authSource = 'authorization_code_exchange';
      await this.persistUserTokens();
      return tokenData;
    } catch (error) {
      if (axios.isAxiosError(error) && error.response?.data) {
        const data = error.response.data as { error?: string; error_description?: string };
        if (data.error_description) {
          throw new Error(data.error_description, { cause: error });
        }
        if (data.error) {
          throw new Error(data.error, { cause: error });
        }
      }
      throw error;
    }
  }

  async refreshUserToken(): Promise<void> {
    if (!this.userTokens) {
      throw new Error('No user tokens available to refresh');
    }

    const authUrl = this.getTokenEndpoint();
    const credentials = Buffer.from(`${this.config.clientId}:${this.config.clientSecret}`).toString(
      'base64'
    );

    const response = await axios.post<EbayUserToken>(
      authUrl,
      new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: this.userTokens.userRefreshToken,
      }).toString(),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          Authorization: `Basic ${credentials}`,
        },
      }
    );

    const tokenData = response.data;
    const now = Date.now();
    this.userTokens = {
      clientId: this.config.clientId,
      clientSecret: this.config.clientSecret,
      redirectUri: this.config.redirectUri,
      userAccessToken: tokenData.access_token,
      userRefreshToken: tokenData.refresh_token || this.userTokens.userRefreshToken,
      tokenType: tokenData.token_type,
      userAccessTokenExpiry: now + tokenData.expires_in * 1000,
      userRefreshTokenExpiry: tokenData.refresh_token_expires_in
        ? now + tokenData.refresh_token_expires_in * 1000
        : this.userTokens.userRefreshTokenExpiry,
      scope: tokenData.scope || this.userTokens.scope,
    };
    await this.persistUserTokens();
  }

  getAuthDebugInfo(): {
    tokenEndpoint: string;
    environment: 'production' | 'sandbox';
    hasClientId: boolean;
    hasClientSecret: boolean;
    hasRefreshToken: boolean;
    hasAccessToken: boolean;
    hasRedirectUri: boolean;
    refreshTokenExpiry?: number;
    accessTokenExpiry?: number;
    source?:
      | 'stored_user_tokens'
      | 'env_refresh_token_fallback'
      | 'authorization_code_exchange'
      | 'manual_set_user_tokens';
  } {
    return {
      tokenEndpoint: this.getTokenEndpoint(),
      environment: this.config.environment,
      hasClientId: this.config.clientId.trim().length > 0,
      hasClientSecret: this.config.clientSecret.trim().length > 0,
      hasRefreshToken: !!this.userTokens?.userRefreshToken,
      hasAccessToken: !!this.userTokens?.userAccessToken,
      hasRedirectUri: !!this.config.redirectUri,
      ...(this.userTokens?.userRefreshTokenExpiry
        ? { refreshTokenExpiry: this.userTokens.userRefreshTokenExpiry }
        : {}),
      ...(this.userTokens?.userAccessTokenExpiry
        ? { accessTokenExpiry: this.userTokens.userAccessTokenExpiry }
        : {}),
      ...(this.authSource ? { source: this.authSource } : {}),
    };
  }

  isAuthenticated(): boolean {
    if (this.userTokens && !this.isUserAccessTokenExpired(this.userTokens)) {
      return true;
    }
    return this.appAccessToken !== null && Date.now() < this.appAccessTokenExpiry;
  }

  clearAllTokens(): void {
    this.appAccessToken = null;
    this.appAccessTokenExpiry = 0;
    this.userTokens = null;
  }

  getTokenInfo(): {
    hasUserToken: boolean;
    hasAppAccessToken: boolean;
    scopeInfo?: { tokenScopes: string[]; environmentScopes: string[]; missingScopes: string[] };
  } {
    const info: {
      hasUserToken: boolean;
      hasAppAccessToken: boolean;
      scopeInfo?: { tokenScopes: string[]; environmentScopes: string[]; missingScopes: string[] };
    } = {
      hasUserToken: this.userTokens !== null && !this.isUserAccessTokenExpired(this.userTokens),
      hasAppAccessToken: this.appAccessToken !== null && Date.now() < this.appAccessTokenExpiry,
    };

    if (this.userTokens?.scope) {
      const tokenScopes = this.userTokens.scope.split(' ');
      const environmentScopes = ['https://api.ebay.com/oauth/api_scope'];
      const tokenScopeSet = new Set(tokenScopes);
      const missingScopes = environmentScopes.filter((scope) => !tokenScopeSet.has(scope));
      info.scopeInfo = { tokenScopes, environmentScopes, missingScopes };
    }

    return info;
  }

  getUserTokens(): StoredTokenData | null {
    return this.userTokens;
  }

  getCachedAppAccessToken(): string | null {
    return this.appAccessToken;
  }

  getCachedAppAccessTokenExpiry(): number {
    return this.appAccessTokenExpiry;
  }
}

import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'fs';
import { dirname, resolve } from 'path';
import type { StoredTokenData } from '@/types/ebay.js';
import { authLogger } from '@/utils/logger.js';

interface PersistedTokenState {
  userTokens: StoredTokenData | null;
  appAccessToken?: string | null;
  appAccessTokenExpiry?: number;
  updatedAt: string;
}

function defaultTokenStorePath(): string {
  return process.env.EBAY_TOKEN_STORE_PATH || resolve(process.cwd(), '.ebay-user-tokens.json');
}

export class EbayTokenStore {
  constructor(private readonly filePath: string = defaultTokenStorePath()) {}

  getPath(): string {
    return this.filePath;
  }

  load(): PersistedTokenState | null {
    try {
      if (!existsSync(this.filePath)) {
        return null;
      }

      const raw = readFileSync(this.filePath, 'utf-8');
      return JSON.parse(raw) as PersistedTokenState;
    } catch (error) {
      authLogger.error('Failed to load token store', {
        path: this.filePath,
        error: error instanceof Error ? error.message : String(error),
      });
      return null;
    }
  }

  save(state: PersistedTokenState): void {
    try {
      mkdirSync(dirname(this.filePath), { recursive: true });
      writeFileSync(
        this.filePath,
        JSON.stringify(
          {
            ...state,
            updatedAt: new Date().toISOString(),
          },
          null,
          2
        ),
        'utf-8'
      );
    } catch (error) {
      authLogger.error('Failed to save token store', {
        path: this.filePath,
        error: error instanceof Error ? error.message : String(error),
      });
    }
  }
}

export type { PersistedTokenState };

/**
 * Token verification using OAuth 2.0 Token Introspection (RFC 7662)
 * and JWT validation
 */

import axios from 'axios';
import * as jose from 'jose';
import type {
  VerifiedToken,
  TokenIntrospectionRequest,
  TokenIntrospectionResponse,
  OAuthServerMetadata,
} from './oauth-types.js';

export interface TokenVerifierConfig {
  /**
   * OAuth authorization server metadata URL or metadata object
   */
  authServerMetadata: string | OAuthServerMetadata;

  /**
   * Client ID for introspection endpoint authentication
   */
  clientId?: string;

  /**
   * Client secret for introspection endpoint authentication
   */
  clientSecret?: string;

  /**
   * Expected audience (resource server URL)
   */
  expectedAudience: string;

  /**
   * Required scopes for access
   */
  requiredScopes?: string[];

  /**
   * Whether to use token introspection (true) or JWT validation (false)
   * Default: true
   */
  useIntrospection?: boolean;
}

export class TokenVerifier {
  private config: TokenVerifierConfig;
  private metadata: OAuthServerMetadata | null = null;

  constructor(config: TokenVerifierConfig) {
    this.config = config;
  }

  /**
   * Initialize the verifier by loading OAuth server metadata
   */
  async initialize(): Promise<void> {
    if (typeof this.config.authServerMetadata === 'string') {
      try {
        const response = await axios.get<OAuthServerMetadata>(this.config.authServerMetadata);
        this.metadata = response.data;
      } catch (error) {
        throw new Error(
          `Failed to load OAuth server metadata: ${error instanceof Error ? error.message : 'Unknown error'}`,
          { cause: error }
        );
      }
    } else {
      this.metadata = this.config.authServerMetadata;
    }
  }

  /**
   * Verify an access token
   */
  async verifyToken(token: string): Promise<VerifiedToken> {
    if (!this.metadata) {
      throw new Error('Token verifier not initialized');
    }

    if (this.config.useIntrospection !== false) {
      return await this.verifyViaIntrospection(token);
    } else {
      return await this.verifyViaJWT(token);
    }
  }

  /**
   * Verify token using OAuth 2.0 Token Introspection (RFC 7662)
   */
  private async verifyViaIntrospection(token: string): Promise<VerifiedToken> {
    if (!this.metadata) {
      throw new Error('Token verifier not initialized');
    }

    // Check if introspection endpoint is available
    const introspectionEndpoint = this.metadata.introspection_endpoint;
    if (!introspectionEndpoint) {
      throw new Error('Introspection endpoint not available in OAuth server metadata');
    }

    // Prepare introspection request
    const requestData: TokenIntrospectionRequest = {
      token,
      token_type_hint: 'access_token',
    };

    // Add client credentials if provided
    const headers: Record<string, string> = {
      'Content-Type': 'application/x-www-form-urlencoded',
    };

    const params = new URLSearchParams({
      token: requestData.token,
    });

    if (this.config.clientId) {
      params.set('client_id', this.config.clientId);
    }

    if (this.config.clientSecret) {
      params.set('client_secret', this.config.clientSecret);
    }

    // Make introspection request
    try {
      const response = await axios.post<TokenIntrospectionResponse>(introspectionEndpoint, params, {
        headers,
      });

      const data = response.data;

      // Check if token is active
      if (!data.active) {
        throw new Error('Token is not active');
      }

      // Validate audience
      if (!this.validateAudience(data.aud)) {
        throw new Error(
          `Invalid audience. Expected: ${this.config.expectedAudience}, Got: ${data.aud}`
        );
      }

      // Validate scopes
      const scopes = data.scope ? data.scope.split(' ') : [];
      if (this.config.requiredScopes) {
        const hasRequiredScopes = this.config.requiredScopes.every((scope) =>
          scopes.includes(scope)
        );
        if (!hasRequiredScopes) {
          throw new Error(
            `Missing required scopes. Required: ${this.config.requiredScopes.join(', ')}, Got: ${scopes.join(', ')}`
          );
        }
      }

      return {
        token,
        clientId: data.client_id || 'unknown',
        scopes,
        expiresAt: data.exp,
        audience: data.aud,
        subject: data.sub,
      };
    } catch (error) {
      if (axios.isAxiosError(error)) {
        throw new Error(
          `Token introspection failed: ${error.response?.data?.error_description || error.message}`,
          { cause: error }
        );
      }
      throw error;
    }
  }

  /**
   * Verify token using JWT validation
   */
  private async verifyViaJWT(token: string): Promise<VerifiedToken> {
    if (!this.metadata) {
      throw new Error('Token verifier not initialized');
    }

    if (!this.metadata.jwks_uri) {
      throw new Error('JWKS URI not available in OAuth server metadata');
    }

    try {
      // Get JWKS from authorization server
      const JWKS = jose.createRemoteJWKSet(new URL(this.metadata.jwks_uri));

      // Verify JWT

      const { payload } = await jose.jwtVerify(token, JWKS, {
        issuer: this.metadata.issuer,
        audience: this.config.expectedAudience,
      });

      // Extract scopes
      const scopes =
        typeof payload.scope === 'string'
          ? payload.scope.split(' ')
          : Array.isArray(payload.scope)
            ? payload.scope
            : [];

      // Validate required scopes
      if (this.config.requiredScopes) {
        const hasRequiredScopes = this.config.requiredScopes.every((scope) =>
          scopes.includes(scope)
        );
        if (!hasRequiredScopes) {
          throw new Error(
            `Missing required scopes. Required: ${this.config.requiredScopes.join(', ')}, Got: ${scopes.join(', ')}`
          );
        }
      }

      return {
        token,
        clientId: (payload.client_id as string) || (payload.azp as string) || 'unknown',
        scopes,
        expiresAt: payload.exp,
        audience: payload.aud,
        subject: payload.sub,
      };
    } catch (error) {
      throw new Error(
        `JWT verification failed: ${error instanceof Error ? error.message : 'Unknown error'}`,
        { cause: error }
      );
    }
  }

  /**
   * Validate audience claim
   */
  private validateAudience(audience: string | string[] | undefined): boolean {
    if (!audience) {
      return false;
    }

    const audiences = Array.isArray(audience) ? audience : [audience];
    const normalizedExpected = this.config.expectedAudience.replace(/\/$/, '');

    return audiences.some((aud) => {
      const normalizedAud = aud.replace(/\/$/, '');
      return (
        normalizedAud === normalizedExpected ||
        normalizedAud === normalizedExpected + '/' ||
        normalizedExpected === normalizedAud + '/'
      );
    });
  }
}

