    // Ad Group Management
    getAdGroupsOutput: zodToJsonSchema(adGroupPagedCollectionResponseSchema, 'getAdGroupsOutput'),
    getAdGroupDetails: zodToJsonSchema(adGroupSchema, 'getAdGroupDetails'),
