      // Set tokens with future expiry
      const futureExpiry = Date.now() + 7200 * 1000;
      await oauthClient.setUserTokens(accessToken, refreshToken, futureExpiry);

      const token = await oauthClient.getAccessToken();

      expect(token).toBe(accessToken);
    });

    it('should refresh expired access token using valid refresh token', async () => {
      const newAccessToken = 'new_access_token';
      const refreshToken = 'user_refresh_token';

      // Set tokens with expired access token but valid refresh token
      const pastExpiry = Date.now() - 1000;
      const futureRefreshExpiry = Date.now() + 18 * 30 * 24 * 60 * 60 * 1000;
      await oauthClient.setUserTokens(
        'expired_token',
        refreshToken,
        pastExpiry,
        futureRefreshExpiry
      );

      // Mock refresh token API call
      mockOAuthTokenEndpoint('sandbox', {
        access_token: newAccessToken,
        token_type: 'Bearer',
        expires_in: 7200,
        refresh_token: refreshToken,
        refresh_token_expires_in: 47304000,
      });

      const token = await oauthClient.getAccessToken();

      expect(token).toBe(newAccessToken);
    });

    it('should throw error when both access and refresh tokens are expired', async () => {
      // Set tokens with both expired
      const pastExpiry = Date.now() - 1000;
      await oauthClient.setUserTokens('expired_access', 'expired_refresh', pastExpiry, pastExpiry);

      await expect(oauthClient.getAccessToken()).rejects.toThrow();
    });

    it('should fallback to client credentials when no user tokens', async () => {
      const clientToken = 'client_credentials_token';
      mockOAuthTokenEndpoint('sandbox', {
        access_token: clientToken,
        token_type: 'Bearer',
        expires_in: 7200,
      });

      const token = await oauthClient.getAccessToken();

      expect(token).toBe(clientToken);
    });

    it('should reuse cached client credentials token if still valid', async () => {
      const clientToken = 'client_credentials_token';
      mockOAuthTokenEndpoint('sandbox', {
        access_token: clientToken,
        token_type: 'Bearer',
        expires_in: 7200,
      });

      // First call - should fetch token
      const token1 = await oauthClient.getAccessToken();
      expect(token1).toBe(clientToken);

      // Second call - should use cached token (no new HTTP call)
      const token2 = await oauthClient.getAccessToken();
      expect(token2).toBe(clientToken);

      // Verify only one HTTP call was made
      expect(nock.pendingMocks().length).toBe(0);
    });
  });

  describe('setUserTokens', () => {
    it('should store user tokens in memory', async () => {
      const accessToken = 'user_access_token';
      const refreshToken = 'user_refresh_token';

      await oauthClient.setUserTokens(accessToken, refreshToken);

      expect(oauthClient.hasUserTokens()).toBe(true);

      // Verify tokens work by getting access token
      const token = await oauthClient.getAccessToken();
      expect(token).toBe(accessToken);
    });

    it('should set default expiry times when not provided', async () => {
      const accessToken = 'user_access_token';
      const refreshToken = 'user_refresh_token';

      await oauthClient.setUserTokens(accessToken, refreshToken);

      // Verify token is available (not expired)
      const token = await oauthClient.getAccessToken();
      expect(token).toBe(accessToken);
    });
  });

  describe('exchangeCodeForToken', () => {
    it('should exchange authorization code for user tokens', async () => {
      const code = 'authorization_code_12345';
      const accessToken = 'exchanged_access_token';
      const refreshToken = 'exchanged_refresh_token';

      mockOAuthTokenEndpoint('sandbox', {
        access_token: accessToken,
        token_type: 'Bearer',
        expires_in: 7200,
        refresh_token: refreshToken,
        refresh_token_expires_in: 47304000,
        scope: 'https://api.ebay.com/oauth/api_scope/sell.inventory',
      });

      const result = await oauthClient.exchangeCodeForToken(code);

      expect(result.access_token).toBe(accessToken);
      expect(result.refresh_token).toBe(refreshToken);
      expect(oauthClient.hasUserTokens()).toBe(true);
    });

    it('should throw error if redirect URI is not configured', async () => {
      const configWithoutRedirect = { ...config, redirectUri: undefined };
      const clientWithoutRedirect = new EbayOAuthClient(configWithoutRedirect);

      await expect(clientWithoutRedirect.exchangeCodeForToken('code_12345')).rejects.toThrow(
        'Redirect URI is required'
      );
    });

    it('should handle OAuth exchange errors', async () => {
      const code = 'invalid_code';

      nock('https://api.sandbox.ebay.com').post('/identity/v1/oauth2/token').reply(400, {
        error: 'invalid_grant',
        error_description: 'Invalid authorization code',
      });

      await expect(oauthClient.exchangeCodeForToken(code)).rejects.toThrow(
        'Invalid authorization code'
      );
    });
  });

  describe('clearAllTokens', () => {
    it('should clear all tokens from memory', async () => {
      // Set tokens first
      await oauthClient.setUserTokens('access_token', 'refresh_token');
      expect(oauthClient.hasUserTokens()).toBe(true);

      await oauthClient.clearAllTokens();

      expect(oauthClient.hasUserTokens()).toBe(false);
    });
  });

  describe('getTokenInfo', () => {
    it('should return token status information when tokens are set', async () => {
      await oauthClient.setUserTokens('access_token', 'refresh_token');
      const info = oauthClient.getTokenInfo();

      expect(info.hasUserToken).toBe(true);
    });

    it('should return info when no tokens are available', () => {
      const info = oauthClient.getTokenInfo();

      expect(info.hasUserToken).toBe(false);
      expect(info.hasAppAccessToken).toBe(false);
    });
  });

  describe('isAuthenticated', () => {
    it('should return true when valid user tokens exist', async () => {
      const futureExpiry = Date.now() + 7200 * 1000;
      await oauthClient.setUserTokens('access_token', 'refresh_token', futureExpiry);

      expect(oauthClient.isAuthenticated()).toBe(true);
    });

    it('should return false when tokens are expired', async () => {
      const pastExpiry = Date.now() - 1000;
      await oauthClient.setUserTokens('expired_access', 'expired_refresh', pastExpiry, pastExpiry);

      expect(oauthClient.isAuthenticated()).toBe(false);
    });

    it('should return false when no tokens are available', () => {
      expect(oauthClient.isAuthenticated()).toBe(false);
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateScopesDetailed,
  getRequiredScopesForTool,
  hasRequiredScopes,
  getScopeDifferences,
  formatScopeForDisplay,
  groupScopesByCategory,
  isScopeReadonly,
  getWriteScope,
  getReadonlyScope,
  getScopeDescription,
} from '@/auth/scope-utils.js';

describe('Scope Utils', () => {
  describe('validateScopesDetailed', () => {
    it('should validate production scopes', () => {
      const result = validateScopesDetailed(
        [
          'https://api.ebay.com/oauth/api_scope/sell.inventory',
          'https://api.ebay.com/oauth/api_scope/sell.fulfillment',
        ],
        'production'
      );

      expect(result.isValid).toBe(true);
      expect(result.validScopes).toHaveLength(2);
      expect(result.invalidScopes).toHaveLength(0);
    });

    it('should detect invalid scopes', () => {
      const result = validateScopesDetailed(
        [
          'https://api.ebay.com/oauth/api_scope/sell.inventory',
          'https://api.ebay.com/oauth/api_scope/invalid.scope',
        ],
        'production'
      );

      expect(result.isValid).toBe(false);
      expect(result.validScopes).toHaveLength(1);
      expect(result.invalidScopes).toContain('https://api.ebay.com/oauth/api_scope/invalid.scope');
    });

    it('should validate sandbox scopes', () => {
      const result = validateScopesDetailed(
        [
          'https://api.ebay.com/oauth/api_scope/sell.inventory',
          'https://api.ebay.com/oauth/api_scope/buy.order.readonly',
        ],
        'sandbox'
      );

      expect(result.validScopes).toContain('https://api.ebay.com/oauth/api_scope/sell.inventory');
    });
  });

  describe('getRequiredScopesForTool', () => {
    it('should return scopes for inventory tools', () => {
      const requirement = getRequiredScopesForTool('ebay_get_inventory_items');

      expect(requirement).toBeDefined();
      expect(requirement?.requiredScopes).toContain(
        'https://api.ebay.com/oauth/api_scope/sell.inventory.readonly'
      );
      expect(requirement?.minimumScope).toBe(
        'https://api.ebay.com/oauth/api_scope/sell.inventory.readonly'
      );
    });

    it('should return scopes for order management tools', () => {
      const requirement = getRequiredScopesForTool('ebay_get_orders');

      expect(requirement).toBeDefined();
      expect(requirement?.requiredScopes).toContain(
        'https://api.ebay.com/oauth/api_scope/sell.fulfillment.readonly'
      );
    });

    it('should return scopes for create/write operations', () => {
      const requirement = getRequiredScopesForTool('ebay_create_inventory_item');

      expect(requirement).toBeDefined();
      expect(requirement?.requiredScopes).toEqual([
        'https://api.ebay.com/oauth/api_scope/sell.inventory',
      ]);
      expect(requirement?.minimumScope).toBe('https://api.ebay.com/oauth/api_scope/sell.inventory');
    });

    it('should return null for unknown tools', () => {
      const requirement = getRequiredScopesForTool('ebay_unknown_tool');
      expect(requirement).toBeNull();
    });

    it('should include optional scopes when applicable', () => {
      const requirement = getRequiredScopesForTool('ebay_publish_offer');

      expect(requirement).toBeDefined();
      expect(requirement?.optionalScopes).toBeDefined();
      expect(requirement?.optionalScopes).toContain(
        'https://api.ebay.com/oauth/api_scope/sell.account'
      );
    });
  });

  describe('hasRequiredScopes', () => {
    it('should return true when token has required scope', () => {
      const tokenScopes = [
        'https://api.ebay.com/oauth/api_scope/sell.inventory',
        'https://api.ebay.com/oauth/api_scope/sell.fulfillment',
      ];

      const result = hasRequiredScopes(tokenScopes, [
        'https://api.ebay.com/oauth/api_scope/sell.inventory',
      ]);

      expect(result).toBe(true);
    });

    it('should return true when token has one of multiple required scopes', () => {
      const tokenScopes = ['https://api.ebay.com/oauth/api_scope/sell.inventory.readonly'];

      const result = hasRequiredScopes(tokenScopes, [
        'https://api.ebay.com/oauth/api_scope/sell.inventory.readonly',
        'https://api.ebay.com/oauth/api_scope/sell.inventory',
      ]);

      expect(result).toBe(true);
    });

    it('should return false when token lacks required scopes', () => {
      const tokenScopes = ['https://api.ebay.com/oauth/api_scope/sell.inventory'];

      const result = hasRequiredScopes(tokenScopes, [
        'https://api.ebay.com/oauth/api_scope/sell.fulfillment',
      ]);

      expect(result).toBe(false);
    });

    it('should handle empty token scopes', () => {
      const result = hasRequiredScopes([], ['https://api.ebay.com/oauth/api_scope/sell.inventory']);

      expect(result).toBe(false);
    });
  });

  describe('getScopeDifferences', () => {
    it('should identify scopes in both environments', () => {
      const diff = getScopeDifferences();

      expect(diff.inBothEnvironments).toBeDefined();
      expect(diff.productionOnly).toBeDefined();
      expect(diff.sandboxOnly).toBeDefined();

      // Sell inventory should be in both
      expect(diff.inBothEnvironments).toContain(
        'https://api.ebay.com/oauth/api_scope/sell.inventory'
      );
    });

    it('should identify production-only scopes', () => {
      const diff = getScopeDifferences();

      // commerce.message is production-only
      if (diff.productionOnly.length > 0) {
        expect(diff.productionOnly).toBeDefined();
      }
    });

    it('should identify sandbox-only scopes', () => {
      const diff = getScopeDifferences();

      // buy.* scopes are typically sandbox-only
      if (diff.sandboxOnly.length > 0) {
        expect(diff.sandboxOnly).toBeDefined();
      }
    });
  });

  describe('formatScopeForDisplay', () => {
    it('should remove common eBay prefix', () => {
      const formatted = formatScopeForDisplay(
        'https://api.ebay.com/oauth/api_scope/sell.inventory'
      );

      expect(formatted).toBe('api_scope/sell.inventory');
    });

    it('should return scope as-is if no prefix', () => {
      const formatted = formatScopeForDisplay('custom:scope');

      expect(formatted).toBe('custom:scope');
    });
  });

  describe('groupScopesByCategory', () => {
    it('should group scopes by category', () => {
      const scopes = [
        'https://api.ebay.com/oauth/api_scope/sell.inventory',
        'https://api.ebay.com/oauth/api_scope/buy.order.readonly',
        'https://api.ebay.com/oauth/api_scope/commerce.identity.readonly',
        'custom:scope',
      ];

      const grouped = groupScopesByCategory(scopes);

      expect(grouped.sell).toContain('https://api.ebay.com/oauth/api_scope/sell.inventory');
      expect(grouped.buy).toContain('https://api.ebay.com/oauth/api_scope/buy.order.readonly');
      expect(grouped.commerce).toContain(
        'https://api.ebay.com/oauth/api_scope/commerce.identity.readonly'
      );
      expect(grouped.other).toContain('custom:scope');
    });

    it('should handle empty array', () => {
      const grouped = groupScopesByCategory([]);

      expect(grouped.sell).toHaveLength(0);
      expect(grouped.buy).toHaveLength(0);
      expect(grouped.commerce).toHaveLength(0);
      expect(grouped.other).toHaveLength(0);
    });
  });

  describe('isScopeReadonly', () => {
    it('should identify readonly scopes', () => {
      expect(isScopeReadonly('https://api.ebay.com/oauth/api_scope/sell.inventory.readonly')).toBe(
        true
      );
      expect(
        isScopeReadonly('https://api.ebay.com/oauth/api_scope/sell.fulfillment.readonly')
      ).toBe(true);
    });

    it('should identify write scopes', () => {
      expect(isScopeReadonly('https://api.ebay.com/oauth/api_scope/sell.inventory')).toBe(false);
      expect(isScopeReadonly('https://api.ebay.com/oauth/api_scope/sell.fulfillment')).toBe(false);
    });
  });

  describe('getWriteScope', () => {
    it('should convert readonly scope to write scope', () => {
      const writeScope = getWriteScope(
        'https://api.ebay.com/oauth/api_scope/sell.inventory.readonly'
      );

      expect(writeScope).toBe('https://api.ebay.com/oauth/api_scope/sell.inventory');
    });

    it('should return null for write scope', () => {
      const writeScope = getWriteScope('https://api.ebay.com/oauth/api_scope/sell.inventory');

      expect(writeScope).toBeNull();
    });
  });

  describe('getReadonlyScope', () => {
    it('should convert write scope to readonly scope', () => {
      const readonlyScope = getReadonlyScope('https://api.ebay.com/oauth/api_scope/sell.inventory');

      expect(readonlyScope).toBe('https://api.ebay.com/oauth/api_scope/sell.inventory.readonly');
    });

    it('should return null for readonly scope', () => {
      const readonlyScope = getReadonlyScope(
        'https://api.ebay.com/oauth/api_scope/sell.inventory.readonly'
      );

      expect(readonlyScope).toBeNull();
    });

    it('should return null for scopes without readonly equivalent', () => {
      const readonlyScope = getReadonlyScope('https://api.ebay.com/oauth/api_scope/sell.edelivery');

      expect(readonlyScope).toBeNull();
    });
  });

  describe('getScopeDescription', () => {
    it('should return description for known scopes', () => {
      expect(getScopeDescription('https://api.ebay.com/oauth/api_scope/sell.inventory')).toBe(
        'View and manage your inventory and offers'
      );

      expect(
        getScopeDescription('https://api.ebay.com/oauth/api_scope/sell.fulfillment.readonly')
      ).toBe('View your order fulfillments');

      expect(
        getScopeDescription('https://api.ebay.com/oauth/api_scope/commerce.identity.readonly')
      ).toBe('View basic user information from eBay account');
    });

    it('should return generic description for unknown scopes', () => {
      const description = getScopeDescription('https://api.ebay.com/oauth/api_scope/unknown.scope');

      expect(description).toBe('Access to unknown.scope');
    });
  });
});

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import axios from 'axios';
import * as jose from 'jose';
import { TokenVerifier } from '@/auth/token-verifier.js';
import type { OAuthServerMetadata } from '@/auth/oauth-types.js';

vi.mock('axios');
vi.mock('jose');

describe('TokenVerifier', () => {
  const mockMetadata: OAuthServerMetadata = {
    issuer: 'http://localhost:8080/realms/master',
    authorization_endpoint: 'http://localhost:8080/realms/master/protocol/openid-connect/auth',
    token_endpoint: 'http://localhost:8080/realms/master/protocol/openid-connect/token',
    jwks_uri: 'http://localhost:8080/realms/master/protocol/openid-connect/certs',
    introspection_endpoint:
      'http://localhost:8080/realms/master/protocol/openid-connect/token/introspect',
  };

  beforeEach(() => {
    vi.clearAllMocks();
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  describe('initialize', () => {
    it('should load metadata from URL', async () => {
      vi.mocked(axios.get).mockResolvedValue({ data: mockMetadata });

      const verifier = new TokenVerifier({
        authServerMetadata: 'http://localhost:8080/realms/master/.well-known/openid-configuration',
        expectedAudience: 'http://localhost:3000',
      });

      await verifier.initialize();

      expect(axios.get).toHaveBeenCalledWith(
        'http://localhost:8080/realms/master/.well-known/openid-configuration'
      );
    });

    it('should use provided metadata object', async () => {
      const verifier = new TokenVerifier({
        authServerMetadata: mockMetadata,
        expectedAudience: 'http://localhost:3000',
      });

      await verifier.initialize();

      expect(axios.get).not.toHaveBeenCalled();
    });

    it('should throw error if metadata loading fails', async () => {
      vi.mocked(axios.get).mockRejectedValue(new Error('Network error'));

      const verifier = new TokenVerifier({
        authServerMetadata: 'http://localhost:8080/realms/master/.well-known/openid-configuration',
        expectedAudience: 'http://localhost:3000',
      });

      await expect(verifier.initialize()).rejects.toThrow(
        'Failed to load OAuth server metadata: Network error'
      );
    });
  });

  describe('verifyToken - introspection', () => {
    it('should verify token via introspection', async () => {
      vi.mocked(axios.get).mockResolvedValue({ data: mockMetadata });
      vi.mocked(axios.post).mockResolvedValue({
        data: {
          active: true,
          client_id: 'test-client',
          scope: 'mcp:tools mcp:admin',
          exp: Math.floor(Date.now() / 1000) + 3600,
          aud: 'http://localhost:3000',
          sub: 'user123',
        },
      });

      const verifier = new TokenVerifier({
        authServerMetadata: 'http://localhost:8080/.well-known/openid-configuration',
        expectedAudience: 'http://localhost:3000',
        clientId: 'mcp-server',
        clientSecret: 'secret',
        requiredScopes: ['mcp:tools'],
        useIntrospection: true,
      });

      await verifier.initialize();
      const result = await verifier.verifyToken('test-token');

      expect(result).toMatchObject({
        token: 'test-token',
        clientId: 'test-client',
        scopes: ['mcp:tools', 'mcp:admin'],
        audience: 'http://localhost:3000',
        subject: 'user123',
      });

      expect(axios.post).toHaveBeenCalledWith(
        mockMetadata.introspection_endpoint,
        expect.any(URLSearchParams),
        { headers: { 'Content-Type': 'application/x-www-form-urlencoded' } }
      );
    });

    it('should reject inactive tokens', async () => {
      vi.mocked(axios.get).mockResolvedValue({ data: mockMetadata });
      vi.mocked(axios.post).mockResolvedValue({
        data: {
          active: false,
        },
      });

      const verifier = new TokenVerifier({
        authServerMetadata: mockMetadata,
        expectedAudience: 'http://localhost:3000',
        useIntrospection: true,
      });

      await verifier.initialize();

      await expect(verifier.verifyToken('invalid-token')).rejects.toThrow('Token is not active');
    });

    it('should reject tokens with invalid audience', async () => {
      vi.mocked(axios.get).mockResolvedValue({ data: mockMetadata });
      vi.mocked(axios.post).mockResolvedValue({
        data: {
          active: true,
          aud: 'http://different-server:3000',
          scope: 'mcp:tools',
        },
      });

      const verifier = new TokenVerifier({
        authServerMetadata: mockMetadata,
        expectedAudience: 'http://localhost:3000',
        useIntrospection: true,
      });

      await verifier.initialize();

      await expect(verifier.verifyToken('test-token')).rejects.toThrow(/Invalid audience/);
    });

    it('should reject tokens with missing scopes', async () => {
      vi.mocked(axios.get).mockResolvedValue({ data: mockMetadata });
      vi.mocked(axios.post).mockResolvedValue({
        data: {
          active: true,
          aud: 'http://localhost:3000',
          scope: 'mcp:tools',
        },
      });

      const verifier = new TokenVerifier({
        authServerMetadata: mockMetadata,
        expectedAudience: 'http://localhost:3000',
        requiredScopes: ['mcp:admin', 'mcp:superuser'],
        useIntrospection: true,
      });

      await verifier.initialize();

      await expect(verifier.verifyToken('test-token')).rejects.toThrow(/Missing required scopes/);
    });

    it('should handle introspection endpoint errors', async () => {
      vi.mocked(axios.get).mockResolvedValue({ data: mockMetadata });
      vi.mocked(axios.post).mockRejectedValue({
        isAxiosError: true,
        response: {
          data: {
            error_description: 'Invalid token',
          },
        },
      });

      vi.mocked(axios.isAxiosError).mockReturnValue(true);

      const verifier = new TokenVerifier({
        authServerMetadata: mockMetadata,
        expectedAudience: 'http://localhost:3000',
        useIntrospection: true,
      });

      await verifier.initialize();

      await expect(verifier.verifyToken('test-token')).rejects.toThrow(
        'Token introspection failed: Invalid token'
      );
    });

    it('should throw error if introspection endpoint not available', async () => {
      const metadataWithoutIntrospection = {
        issuer: 'http://localhost:8080/realms/master',
        authorization_endpoint: 'http://localhost:8080/realms/master/protocol/openid-connect/auth',
        token_endpoint: 'http://localhost:8080/realms/master/protocol/openid-connect/token',
        jwks_uri: 'http://localhost:8080/realms/master/protocol/openid-connect/certs',
      };

      const verifier = new TokenVerifier({
        authServerMetadata: metadataWithoutIntrospection,
        expectedAudience: 'http://localhost:3000',
        useIntrospection: true,
      });

      await verifier.initialize();

      await expect(verifier.verifyToken('test-token')).rejects.toThrow(
        'Introspection endpoint not available'
      );
    });
  });

  describe('verifyToken - JWT', () => {
    it('should verify token via JWT validation', async () => {
      const mockJWKS = vi.fn();
      const mockPayload = {
        iss: mockMetadata.issuer,
        aud: 'http://localhost:3000',
        sub: 'user123',
        client_id: 'test-client',
        scope: 'mcp:tools mcp:admin',
        exp: Math.floor(Date.now() / 1000) + 3600,
      };

      vi.mocked(axios.get).mockResolvedValue({ data: mockMetadata });
      vi.mocked(jose.createRemoteJWKSet).mockReturnValue(mockJWKS as any);
      vi.mocked(jose.jwtVerify).mockResolvedValue({
        payload: mockPayload,
        protectedHeader: {} as any,
      });

      const verifier = new TokenVerifier({
        authServerMetadata: mockMetadata,
        expectedAudience: 'http://localhost:3000',
        requiredScopes: ['mcp:tools'],
        useIntrospection: false,
      });

      await verifier.initialize();
      const result = await verifier.verifyToken('test-jwt-token');

      expect(result).toMatchObject({
        token: 'test-jwt-token',
        clientId: 'test-client',
        scopes: ['mcp:tools', 'mcp:admin'],
        subject: 'user123',
      });

      expect(jose.jwtVerify).toHaveBeenCalledWith('test-jwt-token', mockJWKS, {
        issuer: mockMetadata.issuer,
        audience: 'http://localhost:3000',
      });
    });

    it('should handle scope as array in JWT', async () => {
      const mockJWKS = vi.fn();
      const mockPayload = {
        iss: mockMetadata.issuer,
        aud: 'http://localhost:3000',
        scope: ['mcp:tools', 'mcp:admin'],
        client_id: 'test-client',
        exp: Math.floor(Date.now() / 1000) + 3600,
      };

      vi.mocked(axios.get).mockResolvedValue({ data: mockMetadata });
      vi.mocked(jose.createRemoteJWKSet).mockReturnValue(mockJWKS as any);
      vi.mocked(jose.jwtVerify).mockResolvedValue({
        payload: mockPayload,
        protectedHeader: {} as any,
      });

      const verifier = new TokenVerifier({
        authServerMetadata: mockMetadata,
        expectedAudience: 'http://localhost:3000',
        useIntrospection: false,
      });

      await verifier.initialize();
      const result = await verifier.verifyToken('test-jwt-token');

      expect(result.scopes).toEqual(['mcp:tools', 'mcp:admin']);
    });

    it('should reject JWT with missing scopes', async () => {
      const mockJWKS = vi.fn();
      const mockPayload = {
        iss: mockMetadata.issuer,
        aud: 'http://localhost:3000',
        scope: 'mcp:tools',
        client_id: 'test-client',
        exp: Math.floor(Date.now() / 1000) + 3600,
      };

      vi.mocked(axios.get).mockResolvedValue({ data: mockMetadata });
      vi.mocked(jose.createRemoteJWKSet).mockReturnValue(mockJWKS as any);
      vi.mocked(jose.jwtVerify).mockResolvedValue({
        payload: mockPayload,
        protectedHeader: {} as any,
      });

      const verifier = new TokenVerifier({
        authServerMetadata: mockMetadata,
        expectedAudience: 'http://localhost:3000',
        requiredScopes: ['mcp:admin'],
        useIntrospection: false,
      });

      await verifier.initialize();

      await expect(verifier.verifyToken('test-jwt-token')).rejects.toThrow(
        /Missing required scopes/
      );
    });

    it('should throw error if JWKS URI not available', async () => {
      const metadataWithoutJWKS = {
        issuer: 'http://localhost:8080/realms/master',
        authorization_endpoint: 'http://localhost:8080/realms/master/protocol/openid-connect/auth',
        token_endpoint: 'http://localhost:8080/realms/master/protocol/openid-connect/token',
      };

      const verifier = new TokenVerifier({
        authServerMetadata: metadataWithoutJWKS as OAuthServerMetadata,
        expectedAudience: 'http://localhost:3000',
        useIntrospection: false,
      });

      await verifier.initialize();

      await expect(verifier.verifyToken('test-token')).rejects.toThrow('JWKS URI not available');
    });

    it('should handle JWT verification failures', async () => {
      vi.mocked(axios.get).mockResolvedValue({ data: mockMetadata });
      vi.mocked(jose.createRemoteJWKSet).mockReturnValue(vi.fn() as any);
      vi.mocked(jose.jwtVerify).mockRejectedValue(new Error('Invalid signature'));

      const verifier = new TokenVerifier({
        authServerMetadata: mockMetadata,
        expectedAudience: 'http://localhost:3000',
        useIntrospection: false,
      });

      await verifier.initialize();

      await expect(verifier.verifyToken('invalid-jwt')).rejects.toThrow(
        'JWT verification failed: Invalid signature'
      );
    });

    it('should use azp claim if client_id not present', async () => {
      const mockJWKS = vi.fn();
      const mockPayload = {
        iss: mockMetadata.issuer,
        aud: 'http://localhost:3000',
        azp: 'authorized-party-client',
        scope: 'mcp:tools',
